import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
const API_BASE = 'http://localhost:8000/api/auth';

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------
const AuthContext = createContext(null);

// ---------------------------------------------------------------------------
// Helper ΓÇö build headers with optional JWT bearer token
// ---------------------------------------------------------------------------
function authHeaders(token) {
  const headers = { 'Content-Type': 'application/json' };
  if (token) headers['Authorization'] = `Bearer ${token}`;
  return headers;
}

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------
export function AuthProvider({ children }) {
  const [user, setUser]       = useState(null);
  const [token, setToken]     = useState(() => localStorage.getItem('access_token'));
  const [loading, setLoading] = useState(true);  // true while fetchMe() runs on mount
  const [error, setError]     = useState(null);

  /**
   * Fetch the current user's profile.
   * Called automatically on mount when a stored token exists.
   */
  const fetchMe = useCallback(async (accessToken) => {
    try {
      const res = await fetch(`${API_BASE}/me/`, {
        headers: authHeaders(accessToken),
      });
      if (!res.ok) throw new Error('Session expired');
      const data = await res.json();
      setUser(data.user);
    } catch {
      // Token is invalid or expired ΓÇö clear the session
      localStorage.removeItem('access_token');
      localStorage.removeItem('refresh_token');
      setToken(null);
      setUser(null);
    }
  }, []);

  // On mount: if a token exists in localStorage, validate it by calling /me/
  useEffect(() => {
    if (token) {
      fetchMe(token).finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, [fetchMe, token]);

  /**
   * Register a new account.
   * Returns { success: true, user } on success or { success: false, message } on failure.
   */
  async function register(name, email, password, role = 'user', domain = null) {
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/register/`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, email, password, role, domain }),
      });
      const data = await res.json();
      if (!res.ok) {
        const msg = data.message || data.email?.[0] || 'Registration failed';
        setError(msg);
        return { success: false, message: msg };
      }
      localStorage.setItem('access_token', data.access);
      localStorage.setItem('refresh_token', data.refresh);
      setToken(data.access);
      setUser(data.user);
      return { success: true, user: data.user };
    } catch {
      const msg = 'Network error. Is the server running?';
      setError(msg);
      return { success: false, message: msg };
    }
  }

  /**
   * Log in with email + password.
   * Stores the JWT pair in localStorage and populates the user context.
   */
  async function login(email, password) {
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/login/`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      if (!res.ok) {
        const msg = data.message || 'Login failed';
        setError(msg);
        return { success: false, message: msg };
      }
      localStorage.setItem('access_token', data.access);
      localStorage.setItem('refresh_token', data.refresh);
      setToken(data.access);
      setUser(data.user);
      return { success: true, user: data.user };
    } catch {
      const msg = 'Network error. Is the server running?';
      setError(msg);
      return { success: false, message: msg };
    }
  }

  /**
   * Log out: clear tokens from localStorage and reset context state.
   */
  function logout() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    setToken(null);
    setUser(null);
    setError(null);
  }

  const value = {
    user,
    token,
    loading,
    error,
    login,
    logout,
    register,
    isAuthenticated: !!user,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------
export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside <AuthProvider>');
  return ctx;
}

export default AuthContext;

import { useState, useEffect } from 'react'
import { useAuth } from '../context/AuthContext'

export default function AdminPanel() {
  const { token, user } = useAuth()
  const [users, setUsers] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [patchingId, setPatchingId] = useState(null)

  const DOMAINS = ['Tech Support', 'Finance', 'Marketing', 'Operations', 'Global']
  const ROLES = ['user', 'manager', 'admin']

  useEffect(() => {
    fetchUsers()
  }, [fetchUsers])

  const fetchUsers = async () => {
    setLoading(true)
    try {
      const res = await fetch('http://localhost:8000/api/admin/users/', {
        headers: { 'Authorization': `Bearer ${token}` }
      })
      if (!res.ok) throw new Error('Failed to fetch users')
      const data = await res.json()
      setUsers(data)
    } catch (err) {
      setError(err.message)
    } finally {
      setLoading(false)
    }
  }

  const handleUpdateUser = async (userId, field, value) => {
    setPatchingId(userId)
    try {
      const res = await fetch(`http://localhost:8000/api/admin/users/${userId}/`, {
        method: 'PATCH',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ [field]: value })
      })

      const data = await res.json()
      if (!res.ok) throw new Error(data.message || 'Update failed')

      // Update local state
      setUsers(prev => prev.map(u => u.id === userId ? data : u))
    } catch (err) {
      alert(err.message)
    } finally {
      setPatchingId(null)
    }
  }

  const activeUsersCount = users.filter(u => u.is_active).length
  const managerCount = users.filter(u => u.role === 'manager').length

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-8 animate-pulse">
        <div className="h-8 w-1/4 bg-slate-200 rounded mb-8"></div>
        <div className="h-64 bg-slate-100 rounded-xl"></div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-8 text-rose-600 bg-rose-50 p-6 rounded-xl border border-rose-200">
        <h3 className="font-bold text-lg mb-2">Error Loading Admin Panel</h3>
        <p>{error}</p>
      </div>
    )
  }

  return (
    <div className="w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">

      {/* Header */}
      <div>
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
          <div>
            <h1 className="text-2xl font-bold tracking-tight text-slate-900">User Management</h1>
            <p className="text-slate-500 text-sm mt-1">Manage global access permissions and domain roles.</p>
          </div>
        </div>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="p-5 bg-white border border-slate-200 rounded-xl shadow-sm">
          <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Total Users</p>
          <div className="mt-2 flex items-baseline gap-2">
            <span className="text-2xl font-bold tracking-tight text-slate-900">{users.length}</span>
          </div>
        </div>
        <div className="p-5 bg-white border border-slate-200 rounded-xl shadow-sm">
          <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Active Users</p>
          <div className="mt-2 flex items-baseline gap-2">
            <span className="text-2xl font-bold tracking-tight text-slate-900">{activeUsersCount}</span>
          </div>
        </div>
        <div className="p-5 bg-white border border-slate-200 rounded-xl shadow-sm">
          <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Domain Managers</p>
          <div className="mt-2 flex items-baseline gap-2">
            <span className="text-2xl font-bold tracking-tight text-slate-900">{managerCount}</span>
          </div>
        </div>
        <div className="p-5 bg-white border border-slate-200 rounded-xl shadow-sm">
          <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Admins</p>
          <div className="mt-2 flex items-baseline gap-2">
            <span className="text-2xl font-bold tracking-tight text-slate-900">{users.filter(u => u.role === 'admin').length}</span>
          </div>
        </div>
      </div>

      {/* Data Table */}
      <div className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm relative">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">User</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Role</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Domain</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-center">Status</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 relative">

              {users.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap relative">
                     {patchingId === u.id && (
                        <div className="absolute inset-y-0 left-0 w-1 bg-primary animate-pulse"></div>
                     )}
                    <div className="flex items-center gap-3">
                      <div className="size-8 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-500 text-xs uppercase">
                        {u.name.slice(0, 2)}
                      </div>
                      <div>
                        <p className="text-sm font-semibold text-slate-900">{u.name}</p>
                        <p className="text-xs text-slate-500">{u.email}</p>
                      </div>
                    </div>
                  </td>

                  <td className="px-6 py-4 whitespace-nowrap">
                    <select
                      value={u.role}
                      onChange={e => handleUpdateUser(u.id, 'role', e.target.value)}
                      disabled={u.id === user.id}
                      className={`text-xs font-bold uppercase rounded-md px-2 py-1 border focus:ring-1 focus:ring-primary focus:outline-none transition-colors cursor-pointer disabled:cursor-not-allowed ${
                        u.role === 'admin' ? 'bg-purple-50 text-purple-700 border-purple-200' :
                        u.role === 'manager' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                        'bg-slate-50 text-slate-600 border-slate-200'
                      }`}
                    >
                      {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
                    </select>
                  </td>

                  <td className="px-6 py-4 whitespace-nowrap">
                    <select
                      value={u.domain || ''}
                      onChange={e => handleUpdateUser(u.id, 'domain', e.target.value)}
                      disabled={u.id === user.id && u.role === 'admin'}
                      className="text-sm text-slate-700 bg-transparent border-b border-transparent hover:border-slate-300 focus:border-primary focus:outline-none py-1 cursor-pointer disabled:cursor-not-allowed disabled:hover:border-transparent transition-colors"
                    >
                      <option value="">-- None --</option>
                      {DOMAINS.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                  </td>

                  <td className="px-6 py-4 whitespace-nowrap text-center">
                    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold ${
                      u.is_active ? 'bg-emerald-50 text-emerald-700 border border-emerald-200' : 'bg-rose-50 text-rose-700 border border-rose-200'
                    }`}>
                      <span className={`size-1.5 rounded-full ${u.is_active ? 'bg-emerald-500' : 'bg-rose-500'}`}></span>
                      {u.is_active ? 'Active' : 'Blocked'}
                    </span>
                  </td>

                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm">
                    {u.id !== user.id ? (
                      <button 
                        onClick={() => handleUpdateUser(u.id, 'is_active', !u.is_active)}
                        className={`font-semibold hover:underline transition-colors ${
                          u.is_active ? 'text-rose-600 hover:text-rose-700' : 'text-emerald-600 hover:text-emerald-700'
                        }`}
                      >
                        {u.is_active ? 'Block Access' : 'Restore Access'}
                      </button>
                    ) : (
                      <span className="text-slate-400 italic text-xs">It's You</span>
                    )}
                  </td>
                </tr>
              ))}

            </tbody>
          </table>
        </div>
      </div>

    </div>
  )
}

import { useState, useEffect } from 'react'
import { useParams, Link } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'

export default function QueryDetail() {
  const { id } = useParams()
  const { token, user } = useAuth()

  const [query, setQuery] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  const [commentText, setCommentText] = useState('')
  const [isInternal, setIsInternal] = useState(false)
  const [submittingComment, setSubmittingComment] = useState(false)

  const [patching, setPatching] = useState(false)

  const isManagerOrAdmin = user?.role === 'manager' || user?.role === 'admin'

  const fetchQuery = async () => {
    try {
      const res = await fetch(`http://localhost:8000/api/queries/${id}/`, {
        headers: { 'Authorization': `Bearer ${token}` }
      })
      if (!res.ok) {
        if (res.status === 403) throw new Error('Forbidden: You do not have access to this query.')
        if (res.status === 404) throw new Error('Query not found.')
        throw new Error('Failed to fetch query details')
      }
      const data = await res.json()
      setQuery(data)
    } catch (err) {
      setError(err.message)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchQuery()
  }, [fetchQuery, id, token])

  const handlePostComment = async (e) => {
    e.preventDefault()
    if (!commentText.trim()) return

    setSubmittingComment(true)
    try {
      const res = await fetch(`http://localhost:8000/api/queries/${id}/comments/`, {
        method: 'POST',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ 
          text: commentText, 
          is_internal_note: isInternal 
        })
      })
      if (!res.ok) throw new Error('Failed to post comment')

      const updatedQuery = await res.json()
      setQuery(updatedQuery)
      setCommentText('')
      setIsInternal(false)
    } catch (err) {
      alert(err.message)
    } finally {
      setSubmittingComment(false)
    }
  }

  const handlePatch = async (field, value) => {
    if (!isManagerOrAdmin) return
    setPatching(true)
    try {
      const res = await fetch(`http://localhost:8000/api/queries/${id}/`, {
        method: 'PATCH',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ [field]: value })
      })
      if (!res.ok) throw new Error(`Failed to update ${field}`)

      const updatedQuery = await res.json()
      setQuery(updatedQuery)
    } catch (err) {
      alert(err.message)
    } finally {
      setPatching(false)
    }
  }

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-8 animate-pulse">
        <div className="h-8 w-1/3 bg-slate-200 rounded mb-4"></div>
        <div className="h-64 bg-slate-100 rounded-xl mb-6"></div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="bg-rose-50 border border-rose-200 text-rose-700 p-6 rounded-xl flex items-start gap-4">
          <span className="material-symbols-outlined text-rose-500">error</span>
          <div>
            <h3 className="font-bold text-lg mb-1">Access Denied or Not Found</h3>
            <p>{error}</p>
            <Link to="/my-queries" className="text-primary font-semibold hover:underline mt-4 inline-block">ΓåÉ Back to Queries</Link>
          </div>
        </div>
      </div>
    )
  }

  if (!query) return null

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

      <div className="mb-6">
        <Link to="/my-queries" className="text-sm text-slate-500 hover:text-primary transition-colors flex items-center gap-1 font-medium w-fit">
          <span className="material-symbols-outlined text-sm">arrow_back</span>
          Back to Queries
        </Link>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">

        {/* Main Content (Left) */}
        <div className="flex-1 space-y-6">

          {/* Query Header & Description */}
          <div className="bg-white border border-slate-200 rounded-xl shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100">
              <div className="flex items-center gap-3 mb-3">
                <span className="px-2.5 py-1 rounded bg-slate-100 text-slate-700 text-xs font-bold uppercase tracking-wider">{query.query_id}</span>
                <span className={`px-2.5 py-1 rounded text-xs font-bold uppercase tracking-wider 
                  ${query.status === 'Resolved' ? 'bg-emerald-100 text-emerald-700' 
                  : query.status === 'Open' ? 'bg-blue-100 text-blue-700' 
                  : query.status === 'Closed' ? 'bg-slate-200 text-slate-600'
                  : 'bg-amber-100 text-amber-700'}`}>
                  {query.status}
                </span>
                <span className="text-xs font-semibold text-slate-400">ΓÇó {query.domain}</span>
              </div>
              <h1 className="text-2xl font-bold text-slate-900 mb-2">{query.title}</h1>
              <div className="flex items-center gap-2 text-sm text-slate-500">
                <span className="font-medium text-slate-700">{query.author?.name || 'Unknown User'}</span>
                <span>reported this on</span>
                <span>{new Date(query.created_at).toLocaleString()}</span>
              </div>
            </div>

            <div className="p-6 bg-slate-50/50">
              <h3 className="text-xs font-bold uppercase tracking-wider text-slate-400 mb-3">Description</h3>
              <div className="prose prose-sm max-w-none text-slate-700 whitespace-pre-wrap">
                {query.description}
              </div>
            </div>

            {/* Attachments */}
            {query.attachments && query.attachments.length > 0 && (
              <div className="p-6 border-t border-slate-100">
                <h3 className="text-xs font-bold uppercase tracking-wider text-slate-400 mb-3">Attachments</h3>
                <div className="flex flex-wrap gap-3">
                  {query.attachments.map(att => (
                    <a key={att.id} href={`http://localhost:8000/media/${att.file_path}`} target="_blank" rel="noopener noreferrer"
                      className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-200 rounded-lg hover:border-primary hover:shadow-sm transition-all group">
                      <span className="material-symbols-outlined text-slate-400 group-hover:text-primary transition-colors text-lg">attachment</span>
                      <span className="text-sm font-medium text-slate-700 group-hover:text-primary transition-colors">{att.file_name}</span>
                      <span className="text-xs text-slate-400">({Math.round(att.file_size / 1024)} KB)</span>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Timeline / Comments */}
          <div className="space-y-6">
            <h3 className="text-lg font-bold text-slate-900">Discussion</h3>

            <div className="space-y-4">
              {query.comments && query.comments.length > 0 ? (
                query.comments.map(comment => (
                  <div key={comment.id} className={`p-5 rounded-xl border ${comment.is_internal_note ? 'bg-amber-50/50 border-amber-200' : 'bg-white border-slate-200 shadow-sm'}`}>
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2">
                        <span className="font-semibold text-sm text-slate-900">{comment.author?.name || 'Unknown User'}</span>
                        <span className="text-[10px] uppercase font-bold text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">{comment.author?.role || 'User'}</span>
                        {comment.is_internal_note && (
                          <span className="flex items-center gap-1 text-[10px] uppercase font-bold text-amber-600 bg-amber-100 px-1.5 py-0.5 rounded">
                            <span className="material-symbols-outlined text-[12px]">visibility_off</span>
                            Internal Note
                          </span>
                        )}
                      </div>
                      <span className="text-xs text-slate-400" title={new Date(comment.created_at).toLocaleString()}>
                        {new Date(comment.created_at).toLocaleDateString()}
                      </span>
                    </div>
                    <p className="text-sm text-slate-700 whitespace-pre-wrap">{comment.text}</p>
                  </div>
                ))
              ) : (
                <p className="text-sm text-slate-500 italic">No comments yet. Start the discussion below.</p>
              )}
            </div>

            {/* Add Comment Form */}
            {query.status !== 'Closed' && (
              <form onSubmit={handlePostComment} className="bg-slate-50 border border-slate-200 rounded-xl p-4">
                <textarea
                  rows="3"
                  className="w-full bg-white border border-slate-200 rounded-lg p-3 text-sm focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary/50 transition-all resize-y"
                  placeholder="Write a reply..."
                  value={commentText}
                  onChange={e => setCommentText(e.target.value)}
                  disabled={submittingComment}
                ></textarea>

                <div className="mt-3 flex items-center justify-between">
                  {isManagerOrAdmin ? (
                    <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer">
                      <input 
                        type="checkbox" 
                        className="rounded border-slate-300 text-primary focus:ring-primary"
                        checked={isInternal}
                        onChange={e => setIsInternal(e.target.checked)}
                        disabled={submittingComment}
                      />
                      <span className="font-medium">Make this an internal note</span>
                    </label>
                  ) : <div></div>}

                  <button 
                    type="submit" 
                    disabled={submittingComment || !commentText.trim()}
                    className="px-4 py-2 bg-primary text-white text-sm font-semibold rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50 flex items-center gap-2">
                    {submittingComment ? 'Posting...' : 'Post Reply'}
                    <span className="material-symbols-outlined text-sm">send</span>
                  </button>
                </div>
              </form>
            )}
          </div>
        </div>

        {/* Sidebar (Right) */}
        <div className="w-full lg:w-80 space-y-6">
          <div className="bg-white border border-slate-200 rounded-xl shadow-sm p-5 relative">
            {patching && (
              <div className="absolute inset-0 bg-white/50 backdrop-blur-sm rounded-xl flex items-center justify-center z-10">
                <div className="size-6 border-2 border-primary border-t-transparent rounded-full animate-spin"></div>
              </div>
            )}

            <h3 className="text-sm font-bold text-slate-900 mb-4 border-b border-slate-100 pb-2">Details</h3>

            <div className="space-y-4 text-sm">

              {/* Status */}
              <div>
                <span className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Status</span>
                {isManagerOrAdmin ? (
                  <select 
                    value={query.status} 
                    onChange={e => handlePatch('status', e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 focus:outline-none focus:border-primary focus:bg-white transition-all">
                    <option value="Open">Open</option>
                    <option value="In-Progress">In-Progress</option>
                    <option value="Resolved">Resolved</option>
                    <option value="Closed">Closed</option>
                  </select>
                ) : (
                  <span className="font-semibold text-slate-700">{query.status}</span>
                )}
              </div>

              {/* Priority */}
              <div>
                <span className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Priority</span>
                {isManagerOrAdmin ? (
                  <select 
                    value={query.priority} 
                    onChange={e => handlePatch('priority', e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-semibold text-slate-700 focus:outline-none focus:border-primary focus:bg-white transition-all capitalize">
                    <option value="low">Low</option>
                    <option value="medium">Medium</option>
                    <option value="high">High</option>
                    <option value="critical">Critical</option>
                  </select>
                ) : (
                  <span className="font-semibold text-slate-700 capitalize">{query.priority}</span>
                )}
              </div>

              {/* Assignee - For now, just a text input for ID. Can be enhanced to a user search later */}
              <div>
                <span className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Assignee</span>
                {isManagerOrAdmin ? (
                  <div className="flex gap-2">
                    <input 
                      type="text" 
                      placeholder="User ID..."
                      defaultValue={query.assignee?.id || ''}
                      onBlur={e => handlePatch('assignee_id', e.target.value || null)}
                      className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-medium text-slate-700 focus:outline-none focus:border-primary focus:bg-white transition-all placeholder:font-normal"
                    />
                  </div>
                ) : (
                  <div className="flex items-center gap-2">
                    {query.assignee ? (
                      <span className="font-semibold text-primary bg-primary/10 px-2 py-0.5 rounded text-xs">{query.assignee.name}</span>
                    ) : (
                      <span className="text-slate-400 italic font-medium">Unassigned</span>
                    )}
                  </div>
                )}
                {isManagerOrAdmin && query.assignee && (
                   <p className="text-[10px] text-slate-400 mt-1 pl-1">Currently: {query.assignee.name}</p>
                )}
              </div>

              {/* Category (Read Only for now) */}
              <div>
                <span className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Category</span>
                <span className="text-slate-700 font-medium">{query.category}</span>
              </div>

            </div>
          </div>
        </div>

      </div>
    </div>
  )
}
